"use strict";parserFactory.register("mangallama.com",()=>new MangalamaParser);class MangalamaParser extends Parser{constructor(){super()}getChapterUrls(e){let r=e.querySelector("table.table-striped");return Promise.resolve(util.hyperlinksToChapterList(r).reverse())}findContent(e){return e.querySelector("div#chapcontainer")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("div#titlecontainer").textContent}findCoverImageUrl(e){return e.querySelector("img.img-thumbnail").src}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#description")]}}